class Solution:
    # Helper function to generate permutations using backtracking
    def backtrack(self, nums, used, current, result):
        # If current permutation is complete
        if len(current) == len(nums):
            result.append(current[:])
            return

        # Iterate over all elements
        for i in range(len(nums)):
            # Skip already used elements
            if used[i]:
                continue

            # Include this element
            used[i] = True
            current.append(nums[i])

            # Recurse for next element
            self.backtrack(nums, used, current, result)

            # Backtrack: remove element and mark unused
            current.pop()
            used[i] = False

    # Function to return all permutations
    def permute(self, nums):
        result = []
        used = [False] * len(nums)
        self.backtrack(nums, used, [], result)
        return result

