class Solution {
    // Helper function to generate permutations using backtracking
    backtrack(nums, used, current, result) {
        // If current permutation is complete
        if (current.length === nums.length) {
            result.push([...current]);
            return;
        }

        // Iterate over all elements
        for (let i = 0; i &lt; nums.length; i++) {
            // Skip already used elements
            if (used[i]) continue;

            // Include this element
            used[i] = true;
            current.push(nums[i]);

            // Recurse for next element
            this.backtrack(nums, used, current, result);

            // Backtrack: remove element and mark unused
            current.pop();
            used[i] = false;
        }
    }

    // Function to return all permutations
    permute(nums) {
        const result = [];
        const used = new Array(nums.length).fill(false);
        this.backtrack(nums, used, [], result);
        return result;
    }
}

// Driver code
